const items = $input.all();
return items.map(item => {
  const json = item.json;
  // N8N OpenAI node (DALL-E) returns the URL in different paths depending on version/settings
  let url = json.url;

  if (!url && json.data && Array.isArray(json.data) && json.data.length > 0) {
    url = json.data[0].url;
  }

  if (!url) {
     // Pass the error explicitly to stop execution smoothly or let the HTTP Request fail differently
     throw new Error('No Cover URL found in DALL-E response. Raw response: ' + JSON.stringify(json));
  }

  return { json: { url: url } };
});

const response = $input.first().json;
let content = "";

if (response && response.choices && response.choices.length > 0 && response.choices[0].message) {
  content = response.choices[0].message.content;
}

const bookData = $node["Prepare Cover Prompt"].json;
let refinedPrompt = bookData.prompt;

if (content) {
  refinedPrompt = content
    .replace(/```json\s*/g, '')
    .replace(/```\s*/g, '')
    .replace(/^[\"']|[\"']$/g, '')
    .replace(/{\"refined_prompt\":\s*\"/g, '')
    .replace(/\"}/g, '')
    .trim();
}

if (!refinedPrompt || refinedPrompt.length < 50) {
  refinedPrompt = bookData.prompt;
}

// Max length validation
if (refinedPrompt.length > 3900) {
  refinedPrompt = refinedPrompt.substring(0, 3900);
}

return {
  json: {
    refinedPrompt,
    bookId: bookData.bookId
  }
};

// Estrai i dati del libro e i prompt dal database
const book = $input.first().json;
const prompts = book.prompts || {};

// Costruisci il prompt per la cover partendo dalla base centralizzata
let coverPrompt = prompts.COVER_PREPARATION || "Professional book cover illustration for {{themes}} in {{style}} style.";

const context = book.context_data || {};
const blueprint = context.blueprint || {};
const selectedConcept = context.selected_concept || {};

const truncate = (str, n) => (str && str.length > n) ? str.substring(0, n-1) + '...' : str;

const rawSpecificStyle = selectedConcept.style || blueprint.plot_vibes_or_structure || blueprint.plot_vibes || "professional flat poster illustration";
const specificStyle = truncate(rawSpecificStyle, 200);

const rawThemes = blueprint.themes || 'General subject';
const themes = truncate(rawThemes, 200);

// Iniezione dinamica nel prompt centralizzato
coverPrompt = coverPrompt
    .replace('{{themes}}', themes)
    .replace('{{style}}', specificStyle)
    .replace('{{genre}}', book.genre || 'General');

return {
  json: {
    bookId: book.id,
    title: book.title,
    author: book.author,
    prompt: coverPrompt.trim(),
    promptLength: coverPrompt.length
  }
};

const emojiRegex = /[\uD83C-\uDBFF\uDC00-\uDFFF\u2600-\u26FF\u2700-\u27BF]/g;

const clean = (obj) => {
  if (typeof obj === 'string') {
    return obj.replace(emojiRegex, '');
  }
  if (Array.isArray(obj)) {
    return obj.map(clean);
  }
  if (typeof obj === 'object' && obj !== null) {
    const newObj = {};
    for (const key in obj) {
      newObj[key] = clean(obj[key]);
    }
    return newObj;
  }
  return obj;
};

let rawContent = $node["Agent: Architect"].json.choices[0].message.content || "";

// 1. Remove <think> tags (DeepSeek/Reasoning models)
rawContent = rawContent.replace(/<think>[\s\S]*?<\/think>/g, '');

// 2. Extract JSON using regex
const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error("No JSON found in response: " + rawContent.slice(0, 100));
}

let parsed;
try {
  parsed = JSON.parse(jsonMatch[0]);
} catch (e) {
  throw new Error("Invalid JSON from AI: " + jsonMatch[0].slice(0, 100));
}

return {
  chapters: clean(parsed.chapters || [])
};

