const emojiRegex = /[\uD83C-\uDBFF\uDC00-\uDFFF\u2600-\u26FF\u2700-\u27BF]/g;
let rawContent = $node["Agent: Writer"].json.choices[0].message.content;
// Strip markdown backticks
rawContent = rawContent.replace(/```markdown\n?|```/g, '').trim();
// Strip emojis
const cleanContent = rawContent.replace(emojiRegex, '');
const wordCount = cleanContent.split(/\s+/).filter(w => w.length > 0).length;

return {
  content: cleanContent,
  word_count: wordCount
};

const emojiRegex = /[\uD83C-\uDBFF\uDC00-\uDFFF\u2600-\u26FF\u2700-\u27BF]/g;
let rawContent = $node["Agent: Plotter"].json.choices[0].message.content;
// Strip markdown backticks if present
rawContent = rawContent.replace(/```markdown\n?|```json\n?|```/g, '').trim();
// Strip emojis
const cleanContent = rawContent.replace(emojiRegex, '');

return {
  content: cleanContent
};

const bookData = $node["Get Book Context Concept Architect1"].json;
const dbContext = bookData.context_data || {};
const config = bookData.configuration || {};

const targetPagesRaw = $node["Webhook Router"].json.body.targetPages ?? config.target_pages ?? dbContext.target_pages ?? bookData.target_pages;
const parsedTargetPages = Number(targetPagesRaw);
if (!Number.isFinite(parsedTargetPages) || parsedTargetPages <= 0) {
  throw new Error("targetPages missing/invalid in OUTLINE payload/context");
}
const targetPages = Math.round(parsedTargetPages);

const chaptersRateRaw = $node["Webhook Router"].json.body.configuration?.chaptersRate ?? config.chaptersRate ?? 10;
const chaptersRate = Number(chaptersRateRaw) > 0 ? Number(chaptersRateRaw) : 10;
const wordsPerPage = Number(config.words_per_page) > 0 ? Number(config.words_per_page) : 250;

let numChapters = Number(bookData.target_chapters);
if (!Number.isFinite(numChapters) || numChapters <= 0) {
  numChapters = Math.max(1, Math.floor(targetPages / chaptersRate));
}

const totalWords = targetPages * wordsPerPage;
const wordsPerChapter = Math.floor(totalWords / numChapters);

return {
  json: {
    target_pages: targetPages,
    total_words_target: totalWords,
    num_chapters: numChapters,
    words_per_chapter: wordsPerChapter,
    paragraphs_per_chapter: config.paragraphs_per_chapter || 5,
    debug_inputs: { targetPagesRaw, chaptersRate, config }
  }
};

const reqId = $('Webhook Router').first().json?.body?.requestId;
const rawTargetCount = Number($('Webhook Router').first().json?.body?.targetParagraphCount);
const targetCount = Number.isFinite(rawTargetCount) && rawTargetCount > 0 ? Math.min(25, Math.max(1, Math.round(rawTargetCount))) : null;
if (!reqId) {
  throw new Error('Missing requestId in SCAFFOLD_CHAPTER payload');
}

const extractParagraphs = (payload) => {
  if (!payload) return [];
  if (Array.isArray(payload)) return payload;
  if (Array.isArray(payload.paragraphs)) return payload.paragraphs;
  if (Array.isArray(payload.chapters)) return payload.chapters;
  if (payload.data && Array.isArray(payload.data.paragraphs)) return payload.data.paragraphs;
  if (payload.result && Array.isArray(payload.result.paragraphs)) return payload.result.paragraphs;
  return [];
};

let paras = [];
let parseError = null;

const direct = extractParagraphs($node['Agent: Scaffolder'].json);
if (direct.length > 0) {
  paras = direct;
} else {
  const maybeContent = $node['Agent: Scaffolder'].json?.choices?.[0]?.message?.content;
  if (typeof maybeContent === 'string') {
    try {
      const parsed = JSON.parse(maybeContent.replace(/```json\n?|```/g, '').trim());
      paras = extractParagraphs(parsed);
    } catch (e) {
      parseError = e?.message || 'Invalid JSON from Scaffolder';
    }
  } else if (maybeContent && typeof maybeContent === 'object') {
    paras = extractParagraphs(maybeContent);
  }
}

paras = Array.isArray(paras)
  ? paras.map((p, i) => ({
      title: (p && typeof p.title === 'string' && p.title.trim()) ? p.title.trim() : 'Sottocapitolo ' + (i + 1),
      description: (p && typeof p.description === 'string')
        ? p.description
        : ((p && typeof p.summary === 'string') ? p.summary : '')
    }))
  : [];

if (targetCount && paras.length > targetCount) {
  paras = paras.slice(0, targetCount);
}

const hasParagraphs = paras.length > 0;
const hasEnoughParagraphs = targetCount ? paras.length >= targetCount : hasParagraphs;
const status = hasEnoughParagraphs ? 'completed' : 'failed';
const responseData = hasEnoughParagraphs ? { paragraphs: paras } : null;
const errorMessage = hasEnoughParagraphs
  ? null
  : (parseError || ('Scaffolder produced ' + paras.length + ' paragraphs, expected at least ' + (targetCount || 1)));

const escapedResponse = responseData ? JSON.stringify(responseData).replace(/'/g, "''") : null;
const escapedError = errorMessage ? String(errorMessage).replace(/'/g, "''") : null;

const query = hasEnoughParagraphs
  ? "UPDATE ai_requests SET status = 'completed', response_data = '" + escapedResponse + "'::jsonb, error_message = NULL, updated_at = NOW() WHERE id = '" + reqId + "'::uuid;"
  : "UPDATE ai_requests SET status = 'failed', response_data = NULL, error_message = '" + escapedError + "', updated_at = NOW() WHERE id = '" + reqId + "'::uuid;";

return { json: { query, status, requestId: reqId, paragraphs_count: paras.length } };

// Build a robust OpenAI payload for SCAFFOLD_CHAPTER with explicit JSON schema instructions.
const webhookBody = $('Webhook Router').first().json?.body || {};
const context = $('Get Book Context (Scaffolder)').first().json || {};
const primaryModel = context.primary_model || 'gpt-4o';
const prompts = context.prompts || {};
const temps = context.temps || {};

const chapterTitle = webhookBody.chapter?.title || 'Capitolo Sconosciuto';
const chapterSummary = webhookBody.chapter?.summary || '';
const feedback = webhookBody.feedback || 'Nessun feedback. Genera da zero.';
const rawTargetCount = Number(webhookBody.targetParagraphCount);
const targetCount = Number.isFinite(rawTargetCount) && rawTargetCount > 0 ? Math.min(25, Math.max(1, Math.round(rawTargetCount))) : 5;

const ragChunks = $('RAG: Query Scaffold').all()
  .map(item => (item?.json?.content ? String(item.json.content) : ''))
  .filter(Boolean)
  .join('  ');

const systemPrompt = prompts.SCAFFOLDER || "Sei l'Architetto Letterario W4U.";

const schemaInstruction = [
  'Rispondi SOLO con JSON valido, senza markdown e senza testo extra.',
  'Schema obbligatorio:',
  '{"paragraphs":[{"title":"string","description":"string"}]}',
  'Genera ESATTAMENTE ' + targetCount + ' elementi in paragraphs.'
].join('\n');

const userContent = [
  'DATA:',
  'BLUEPRINT: ' + JSON.stringify(context.context_data || {}),
  'PLOT SUMMARY: ' + (context.plot_summary || ''),
  'CURRENT CHAPTER: ' + chapterTitle + ' - ' + chapterSummary,
  'RAG CONTEXT: ' + ragChunks,
  'FEEDBACK/INSTRUCTION: ' + feedback,
  schemaInstruction
].join('\n\n');

const openaiPayload = {
  model: primaryModel,
  max_tokens: 4000,
  temperature: temps.SCAFFOLDER || 0.7,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userContent }
  ]
};

return { json: openaiPayload };

const text = $node["Webhook Router"].json.body.textContent || "";
const bookId = $node["Webhook Router"].json.body.bookId;
const chunkSize = 1000;
const chunks = [];

for (let i = 0; i < text.length; i += chunkSize) {
  chunks.push({
    textContent: text.substring(i, i + chunkSize),
    bookId: bookId,
    chunkIndex: Math.floor(i / chunkSize)
  });
}

return chunks.map(c => ({ json: c }));

